INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-c5fb3965-moex-00111', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「重山曲流外就是苦樂混合著沸騰的紅塵，那裡面也有著我的妻女和親 友，而我卻一個人上山來獨自享受清靜。那麼，我的幸福是不是純由逃避 式的懶散得來的呢？」 根據上文，下列選項最符合作者心理的是：', '["竊喜", "反思", "痛苦", "超然"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00112', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「鞋子的款式，自然顯露了一個人的品味與內涵，但也同時代表了一個人 的心靈狀況。年輕時，總是希望穿著『正式』，讓人家不要一眼看穿我因 缺乏經驗而惶恐的心；也不要認為我無知失禮或不合時宜。但現在慢慢不 再講究了，反而是希望以便捷、舒適為主要考量，到哪都踏著一雙便鞋， 也許就宣示了大叔的天真無畏，諸法皆空。」 根據上文，下列選項何者最符合文意？', '["年輕人相較年長者只追求鞋子的外型", "年長男性不甚講究衣著的正式與流行", "鞋子的樣式呈現出此人的性格與需求", "鞋子的設計最能反映當代的美學趨勢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00113', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「從與土地及自然相處長出來的知識，是一本怎麼也讀不完的書。地方的 農民往往會說『蘿蔔紮地生長後不能澆太多水，否則會長出像人蔘般的多 根』、『高麗菜在包心的時候也是數日一澆，要不菜心就爆開了』、『菜 苗長出來之後要勤快拔雜草，三兩天拔一次』。在馬祖也可見證大自然的 慷慨與偶爾的無情翻臉，譬如霧季時的十分鐘一氣象，你得順著時節、按 著節奏、勤著腳步、聽著建議、耐著心情，然後作物就會一季季回饋你的 累。」 根據上文，下列選項何者最符合文意？', '["只要用心勤快對待作物，並能吸取種植經驗，作物會以豐收回饋", "蘿蔔、高麗菜等作物無需花費太多心思，只要澆灌就會長得很好", "農作知識靠口耳相傳，正確性不高，照書本種植比較不容易出錯", "必須突破氣候的限制，不分四季殷勤耕耘，才能種出優良的作物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00114', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「一面走動，跟緊外婆怕跟丟，一面忙吃。冰在糖漿裡瞬間就化水，不時 吮一口融冰，才不會走著走著晃出來。且記得把冰遞回給外婆，她也吃上 幾口。這種含糖時刻是祖孫倆放風的樂趣，彼此掩護是為溺愛。兒時的米 苔目時光，都與我外婆一道。長大生出了自己的偏好，多年不吃，兼排斥 一切粗麵。麵吃細麵，吃粉就選米粉米線。米苔目這白胖的粉食，跟粗米 粉被我歸成同一路，覺得味道寡淡。現在回頭去找米苔目，懷念的仍不是 味道，而是童年。」 根據上文，下列選項最符合文意的是：', '["米苔目冰能緩緩化水，吮飲融冰是作者童年時的一大樂趣", "外婆和幼年作者常被禁止吃糖，因此會一起偷吃米苔目冰", "作者雖不愛吃粗麵和粗米粉，仍愛品嚐滋味清淡的米苔目", "作者長大後吃米苔目，除了懷念味道，也是紀念童年時光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00115', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「節約不盡然是苦行僧式的刻苦。我的意思是說，刻苦的概念必然包含抗 拒豐饒的誘惑：拒絕太多食物、太多富足、太多財物、太多享樂。刻苦的 人譴責享樂，認為它容易導致放縱。因此必須節制，減量，排除。刻苦的 概念有一大成分是嚴峻，一種對樂趣的輕視乃至恐懼。刻苦是拒絕自我解 放，禁止讓自己感受程度太深，以免無法節制。節制則是發現簡單能夠帶 來滿足，發現人可以幾乎一無所有——只有一杯清水，一顆水果，一陣涼 風——卻感到無比幸福。」 根據上文，下列選項何者正確？', '["追求刻苦的人生，可拒絕豐饒的誘惑，因而能享受富足", "刻苦的目的是為了讓生活更為簡單，因此完全拒絕生活的享樂", "「節約」是發現簡單能帶來幸福，而不是刻意讓自己感到匱乏與痛苦", "我們應當學習苦行僧式的生活態度，才能讓生活變得更為簡約而自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00116', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「有首曲子，希望用在我的葬禮上。這是第一首讓我大哭的音樂——貝多 芬的『皇帝』鋼琴協奏曲。標題被安上『皇帝』，是因為它誇張的特色。 曲子首尾兩樂章，音符充耳，如煙火散落；中間的第二樂章，極美，平靜， 讓人屏息。我那時比較年輕，不大能駕馭，現在我已長大，音樂能做什麼， 全展現其中。」 根據上文，下列選項最符合文意的是：', '["鋼琴家希望葬禮隆重，樂曲具莊嚴堂皇之風，以切合他的身分", "鋼琴家自認要到晚年，才能駕馭貝多芬炫麗的「皇帝」協奏曲", "貝多芬失聰後作的「皇帝」協奏曲，高低起伏，令鋼琴家仰慕", "「皇帝」協奏曲兼具燦爛、平靜曲風，適合詮釋鋼琴家的一生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00117', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「善良的人無法喜愛一件新的作品，但當這作品問世二十年後卻又真誠地 喜愛它，這是常有的事。新生命的香味太濃了，他們虛弱的頭腦承受不了， 香氣會隨著時間的流逝而漸漸揮發掉。藝術品只有在覆滿陳年積垢時才會 被他們理解。」 根據上文，下列選項何者最符合文意？', '["人類大多是善變無常", "只有強者才善於創造", "創作者難免承受孤獨", "善良無助於評價優劣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00118', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「雖然組織胺的主要任務是保護身體的安全，但是這些保鑣有時對很多東 西都視為威脅。例如飄在空氣中的花粉，或家中寵物的毛髮、皮屑，組織 胺都想要把它們擋在身體之外，而下達排除的指令。這些會引發身體組織 胺大量分泌的外界物質稱為『過敏原』，這些物質引發的身體反應稱為『過 敏』。」 根據上文，下列選項何者與上文所言相抵觸？', '["組織胺就像體內保鑣多多益善", "過敏原會引發身體大量分泌組織胺", "花粉或寵物的毛髮、皮屑都有可能是過敏原", "過敏是對自然環境中的過敏原產生反應的現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00119', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '村上春樹曾說過：「不管多大年紀都無所謂，無非就是個恰到好處的人罷 了。」不必非得去裝年輕，也不必去感慨歲月滄桑，「花開花落自有時」， 追隨大自然的規律，一切都剛剛好！ 根據上文，下列選項最符合文意的是：', '["健康長壽是老年人最大的幸福", "努力改變自己，讓自己活得更精彩", "不管什麼年齡，接納自己，好壞都自有安排", "年輕時就該為老年計劃，才不至於老大徒傷悲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00120', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-34c7f7f6', 'sub-disabled-c5fb3965-03', NULL, 'single_choice', '「電車通過櫻花隧道之際，也讓人湧起一股如夢似幻的感受，難道這輛穿 越花海的電車，最終會開往夢幻天堂？京都的美經常給人一種不真實感， 美到讓人無法呼吸，讓人無法忍受，最後不得不像《金閣寺》裡的小和尚， 忍不住一把火將金閣寺燒掉！日本的櫻花美學就是要去擁抱、珍惜短暫的 極致美感，美的極致之後，就不在乎毀滅或死亡了！」 根據上文，下列選項何者最符合文意？', '["櫻花盛開有如熊熊火焰，似乎要將一切景物吞沒殆盡", "櫻花盛開時的美感極為短暫虛幻，所以不能沉迷其中", "人們若曾經領略如櫻花盛放的美好片刻，就了無遺憾", "小和尚在櫻花盛開之時縱火焚寺，是殉美的極致表現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
